// src/components/Sponsors.jsx
import './Sponsors.css';

const whyCards = [
  { icon: '📣', title: 'Brand Visibility', desc: 'Logo placement on all event materials, website, and social media reaching 10,000+ impressions.' },
  { icon: '🎓', title: 'Talent Access', desc: 'Direct access to 500+ pre-screened, AI-literate developers and designers actively building.' },
  { icon: '🤝', title: 'Hiring Pipeline', desc: 'Set up a recruitment booth, host a workshop, or run a sponsored challenge to find your next hire.' },
  { icon: '🌐', title: 'Ecosystem Impact', desc: "Position your brand at the forefront of the AI development wave in India's growing tech scene." },
];


const placeholderLogos = ['ARTHANTA TECH'];

export default function Sponsors() {
  return (
    <section id="sponsors" className="sponsors-section">
      <p className="section-tag">Partnership</p>
      <h2 className="section-title">
        Advertise & <span className="gradient-text">Sponsor</span>
      </h2>
      <p className="section-desc">
        Join India's most exciting AI hackathon as a partner. Reach 500+ talented
        developers, designers, and innovators all in one room.
      </p>

      {/* Why sponsor */}
      <div className="why-grid fade-in">
        {whyCards.map(({ icon, title, desc }) => (
          <div className="why-card card" key={title}>
            <div className="why-icon">{icon}</div>
            <h4>{title}</h4>
            <p>{desc}</p>
          </div>
        ))}
      </div>

      {/* Tiers */}
      <h3 className="tiers-heading">Sponsorship <span className="gradient-text">Tiers</span></h3>
      <div className="tiers-grid fade-in">
        {tiers.map(({ tier, cls, badge, price, desc, perks }) => (
          <div className={`tier-card tier-card--${cls}`} key={tier}>
            <span className={`tier-badge tier-badge--${cls}`}>{badge}</span>
            <div className={`tier-price tier-price--${cls}`}>{price}</div>
            <p className="tier-desc">{desc}</p>
            <ul className="tier-perks">
              {perks.map((p) => <li className={`perk--${cls}`} key={p}>{p}</li>)}
            </ul>
            <button className={`tier-btn tier-btn--${cls}`}>
              Become {tier} Partner
            </button>
          </div>
        ))}
      </div>

      {/* Placeholder logos */}
      <p className="current-sponsors-label">Current Partners</p>
      <div className="sponsor-logos">
        {placeholderLogos.map((l) => (
          <div className="sponsor-logo-box" key={l}>{l}</div>
        ))}
      </div>
    </section>
  );
}
